import { TestScheduler } from "rxjs/testing";
import { Observable, switchMap } from "rxjs";

const ts = new TestScheduler((a: unknown, e: unknown) => {
  if (JSON.stringify(a) !== JSON.stringify(e)) throw new Error("mismatch");
});

ts.run(({ cold, expectObservable }) => {
  const outer$: Observable<string> = cold("-a-b|", { a: "x", b: "y" });
  const result$ = outer$.pipe(
    switchMap((v: string) => cold("--r|", { r: v.toUpperCase() }))
