import { Observable, throwError, of, catchError } from "rxjs";

interface User {
  id: string;
  name: string;
}

const failing$: Observable<User> = throwError(() => new Error("network down"));
const fallback$: Observable<User> = of({ id: "anon", name: "Guest" });

const safe$: Observable<User> = failing$.pipe(
  catchError((err: unknown) => {
    void err;
    return fallback$;
  })
);

safe$.subscribe((u: User) => {
  void u;
});
```

Pass a factory function to throwError. The factory runs once per subscription, so heavy Error construction is deferred. Combine with catchError to recover.

```typescript
import { Observable, throwError, of, catchError } from "rxjs";

const lazy$: Observable<number> = throwError(() => new Error("boom"));

const recovered$: Observable<number> = lazy$.pipe(
  catchError((err: unknown) => {
    void err;
    return of(-1);
  })
);

recovered$.subscribe((n: number) => {
  void n;
});
```

Inside catchError, you return an observable that will replace the failing stream. If you want to rethrow (possibly with a wrapped/enriched error), simply return throwError(() => wrap(e)). Downstream consumers then see the wrapped error via their error handler.

