  constructor(public field: string) {
    super(`invalid ${field}`);
  }
}

const input$: Observable<number> = of(1, -2, 3);

const validated$: Observable<number> = input$.pipe(
  mergeMap((n: number): Observable<number> =>
    n >= 0 ? of(n) : throwError(() => new ValidationError("n"))
  ),
  catchError((e: unknown) => { void e; return of(-1); })
);

validated$.subscribe((v: number) => { void v; });
