  source: "live" | "cache";
  value: number;
}

const live$: Observable<Snapshot> = of({ source: "live" as const, value: 1 });
const cached$: Observable<Snapshot> = of({ source: "cache" as const, value: 0 });

function source$(isOnline: boolean): Observable<Snapshot> {
  return iif(() => isOnline, live$, cached$);
